import json
import os

# --- Configuration ---
# Update this to match the filename generated by your scraping script
INPUT_FILENAME = '/Users/hdon/Projects/Firebase/real-time/bsky-firehose/python/bsky/datasets/my_posts/newenglandtopnews_bsky_social_posts_07-16-2026-2.jsonl'
OUTPUT_FILENAME = '/Users/hdon/Projects/Firebase/real-time/bsky-firehose/python/bsky/datasets/my_posts/newenglandtopnews_com_posts_07-16-2026-2_posts.txt'


def extract_original_posts(input_file, output_file):
    if not os.path.exists(input_file):
        print(f"Error: Could not find the input file '{input_file}'")
        print("Please make sure the scraping script has run first and generated this file.")
        return

    total_processed = 0
    match_count = 0

    try:
        with open(input_file, 'r', encoding='utf-8') as infile, \
                open(output_file, 'w', encoding='utf-8') as outfile:

            print(f"Reading from {input_file}...")

            for line in infile:
                line = line.strip()
                if not line:
                    continue  # Skip any accidental empty lines

                total_processed += 1
                post_data = json.loads(line)

                # We extract our boolean flags, defaulting to False if they are missing
                is_reply = post_data.get('is_reply', False)
                is_repost = post_data.get('is_repost', False)
                is_quote_repost = post_data.get('is_quote_repost', False)

                # Check if it is a purely original, standalone post
                if not is_reply and not is_repost and not is_quote_repost:
                    url = post_data.get('url')
                    if url:
                        outfile.write(url + '\n')
                        match_count += 1

        print("\n--- Processing Complete ---")
        print(f"Total posts analyzed: {total_processed}")
        print(f"Original posts found: {match_count}")
        print(f"Saved URLs to:        {output_file}")

    except Exception as e:
        print(f"An error occurred while processing: {e}")


if __name__ == "__main__":
    extract_original_posts(INPUT_FILENAME, OUTPUT_FILENAME)